/* CSR-less spin fixture for the F5 plugin-icount e2e. Links at
 * 0x00100000 (1 MiB into andes_ae350 DRAM, matching rt_c.ld); avoids
 * the MROM at 0x80000000 that fires the "ROM regions overlapping"
 * error when an ELF is loaded via -bios on andes_ae350. */

ENTRY(_start)

SECTIONS {
    . = 0x00100000;
    .text : { *(.text*) }
    /DISCARD/ : { *(.*) }
}

/* C-runtime linker script for hybrid round-trip fixtures.
 *
 * Loads at 0x00100000 (1 MiB into andes_ae350 DRAM, which starts at
 * 0x00000000 and extends to 0x80000000). Also inside vsim's RAM region
 * RAM_BASE..RAM_END = 0x0..0x8FFFFFFF. Preserves .data/.bss/.rodata so C
 * programs with global state can link, and exposes _edata/_end (consumed by
 * crt0.S's bss-clear loop) and _stack (consumed by crt0.S's sp init).
 *
 * Note: this layout deliberately keeps everything below 0x80000000 so it
 * does not collide with AE350's MROM region (0x80000000..0x88000000).
 * V_SCRATCH at 0x00FF0000 (RAM_BASE + 0xFF0000) is reserved by
 * v_regfile_xfer.hpp / .c; keep _stack and BSS below that.
 */

ENTRY(_start)

SECTIONS {
    . = 0x00100000;

    .text : {
        *(.text.init)
        *(.text*)
    }

